module adder_8bit
(
    input [7:0] a,
    input [7:0] b,
    input cin,
    output [7:0] sum,
    output cout
);

    wire [8:0] carry;
    assign carry[0] = cin;

    genvar i;
    generate
        for (i = 0; i < 8; i = i + 1) begin : adder_block
            wire [7:0] temp_sum;
            wire temp_cout;
            assign {temp_cout, temp_sum[i]} = a[i] + b[i] + carry[i];
            assign sum[i] = temp_sum[i];
            assign carry[i + 1] = temp_cout;
        end
    endgenerate

    assign cout = carry[8];

endmodule
